function initializeTOC(){const body=document.body;if(!body||!body.classList.contains("toc-enabled")){return}const contentEntry=document.querySelector(".content__entry");if(!contentEntry)return;if(contentEntry.querySelector(".toc-wrapper")){return}const h2s=Array.from(contentEntry.querySelectorAll("h2")).filter(h2=>{if(!h2.parentElement)return false;if(h2.parentElement.classList.contains("content__entry"))return true;if(h2.parentElement.tagName.toLowerCase()!=="div")return true;return false});if(h2s.length===0){return}if(typeof TOCWrapper==="undefined"){return}const tocWrapper=new TOCWrapper;const toc=tocWrapper.init();if(toc&&typeof TOCSticky!=="undefined"){new TOCSticky(toc)}}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",initializeTOC)}else{initializeTOC()}